"""Decorators for RBAC enforcement in API routes."""

from functools import wraps
# from .evaluator import RBACEvaluator  # TODO: uncomment when evaluator is ready


def require_permission(resource: str):
    """Decorator that checks if the current user has the specified permission.

    Usage:
        @require_permission('grant:read')
        def get_grant(grant_id):
            ...
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # TODO: integrate with RBACEvaluator
            # evaluator = RBACEvaluator()
            # user = get_current_user()
            # if not evaluator.has_permission(user, resource):
            #     raise PermissionDeniedError(f"Access denied to {resource}")
            return func(*args, **kwargs)
        return wrapper
    return decorator

{
  "roles": [
    {
      "name": "viewer",
      "description": "Can view grants and basic information",
      "permissions": [
        {"resource": "grant:read", "effect": "allow"},
        {"resource": "budget:read", "effect": "allow"},
        {"resource": "report:read", "effect": "allow"}
      ]
    },
    {
      "name": "researcher",
      "description": "Can view and submit grants",
      "parents": ["viewer"],
      "permissions": [
        {"resource": "grant:write", "effect": "allow"},
        {"resource": "grant:submit", "effect": "allow"}
      ]
    },
    {
      "name": "department_head",
      "description": "Can approve grants within department",
      "parents": ["researcher"],
      "permissions": [
        {"resource": "grant:approve", "effect": "allow"},
        {"resource": "budget:write", "effect": "allow"}
      ]
    },
    {
      "name": "finance_auditor",
      "description": "Can view financial data but cannot modify grants",
      "parents": ["viewer"],
      "permissions": [
        {"resource": "budget:audit", "effect": "allow"},
        {"resource": "grant:write", "effect": "deny"},
        {"resource": "grant:submit", "effect": "deny"}
      ]
    },
    {
      "name": "compliance_officer",
      "description": "Inherits from department_head but denied budget write for separation of duties",
      "parents": ["department_head"],
      "permissions": [
        {"resource": "compliance:review", "effect": "allow"},
        {"resource": "budget:write", "effect": "deny"}
      ]
    },
    {
      "name": "restricted_auditor",
      "description": "Inherits from compliance_officer, should still have budget:write denied through hierarchy",
      "parents": ["compliance_officer"],
      "permissions": [
        {"resource": "audit:full", "effect": "allow"}
      ]
    },
    {
      "name": "institution_admin",
      "description": "Full administrative access",
      "parents": ["department_head"],
      "permissions": [
        {"resource": "admin:manage_users", "effect": "allow"},
        {"resource": "admin:manage_roles", "effect": "allow"},
        {"resource": "admin:system_config", "effect": "allow"}
      ]
    }
  ]
}
